sys_script_include.script:
var SPEntryPage = Class.create();
SPEntryPage.prototype = {
    initialize: function() {},

    // This native function controls where the user lands after typing their password
    getFirstPageURL: function() {
        var currentUser = gs.getUser();

        // If they are a public citizen (external user), drop them right into the catalog tracking views
        if (currentUser.hasRole('snc_external')) {
            return '/sp?id=sc_category';
        }

        // If they are an administrator or fulfiller staff, let them go to the default homepage
        return '/sp';
    },

    type: 'SPEntryPage'
};
